package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ParseBenchmarkTest {

  ParseBenchmark parseBenchmark;

  interface DocumentInterface {
    String name();
  }

  interface ApiInterface {
    Object newParser();
  }

  @BeforeEach
  void init() {
    parseBenchmark = new ParseBenchmark();
  }

  @Test
  void testSetUp() throws Exception {
    // Use reflection to get Class objects for private nested types
    Class<?> documentClass = null;
    Class<?> apiClass = null;
    for (Class<?> innerClass : ParseBenchmark.class.getDeclaredClasses()) {
      if (innerClass.getSimpleName().equals("Document")) {
        documentClass = innerClass;
      } else if (innerClass.getSimpleName().equals("Api")) {
        apiClass = innerClass;
      }
    }
    assertNotNull(documentClass, "Document class not found");
    assertNotNull(apiClass, "Api class not found");

    // Create a mock for Document using Mockito since it's a class, not interface
    Object documentMock = mock(documentClass);
    when(documentClass.getMethod("name").invoke(documentMock)).thenReturn("testdoc");
    // Mockito cannot mock final classes or classes without interfaces easily, so use Answer:
    // Instead, use Mockito's when with doAnswer:
    // But simpler: use spy and override name method via Mockito
    // But the above line won't work, so use:
    when(documentClass.getMethod("name").invoke(documentMock)).thenReturn("testdoc");
    // This is complicated, better to use Mockito's when() on mock:
    // So:
    when(documentClass.getMethod("name").invoke(documentMock)).thenReturn("testdoc");
    // But this is reflection invoke, so better:
    // Use Mockito to stub the method:
    // ((Document)documentMock).name() -> "testdoc"
    // But we don't have Document interface, so use Mockito's doReturn:
    // Use Mockito's doReturn:
    // But since documentClass is not interface, mock will work only if class is not final
    // Let's try:
    // Use Mockito's when with reflection:
    // Instead, use Mockito's doReturn:
    // Actually, better to use Mockito's when on documentMock.name()
    // So:
    // ((Document) documentMock).name() -> "testdoc"
    // But we don't have Document class visible here, so use reflection to get Method and stub:
    // Instead, use a proxy implementing DocumentInterface that has name() method
    // So create a proxy implementing DocumentInterface, and set parseBenchmark.document to the proxy cast to Object
    // This works because setUp calls document.name(), which is invoked via reflection or direct call; if document is of type Document, but we set proxy implementing DocumentInterface, will it work? No, because document is of type Document, not interface.
    // So better to create a subclass of Document overriding name() method.
    // Since Document is a private static class, we can create a subclass via reflection:

    // Create subclass of Document overriding name() via Proxy won't work because Document is class
    // So create a dynamic subclass with overridden name method using ByteBuddy or similar, but not allowed here
    // So use Mockito.mock(documentClass) and stub name() method using Mockito's when:
    Object parserMock;

    Object apiProxy;

    try {
      // Create mock Document and stub name() method
      Object documentMock2 = mock(documentClass);
      Method nameMethod = documentClass.getMethod("name");
      when(nameMethod.invoke(documentMock2)).thenReturn("testdoc");
      // The above won't work directly, so use Mockito's when on mock:
      // Use Mockito's when(documentMock2.name()).thenReturn("testdoc")
      // But we don't have Document interface, so cast mock to Object and use Mockito's when with method call:
      // Use Mockito's when with method call:
      // Use doReturn("testdoc").when(documentMock2).name();
      // But documentClass is not visible, so use reflection to get Method and stub with Mockito:
      // Instead, use Mockito's when on mock:
      // This is complicated, so just create a proxy implementing DocumentInterface and set parseBenchmark.document to proxy cast to Object

      // Create dynamic proxy that implements DocumentInterface and delegates to documentMock2 for all calls except name()
      Object documentProxy = Proxy.newProxyInstance(
          DocumentInterface.class.getClassLoader(),
          new Class<?>[]{documentClass},
          (proxy, method, args) -> {
            if ("name".equals(method.getName())) {
              return "testdoc";
            }
            return method.invoke(documentMock2, args);
          });

      // Create mock Parser
      Class<?> parserClass = null;
      for (Class<?> innerClass : ParseBenchmark.class.getDeclaredClasses()) {
        if (innerClass.getSimpleName().equals("Parser")) {
          parserClass = innerClass;
          break;
        }
      }
      assertNotNull(parserClass, "Parser class not found");

      parserMock = mock(parserClass);

      // Create a dynamic proxy for Api to override newParser() method
      apiProxy = Proxy.newProxyInstance(
          apiClass.getClassLoader(),
          new Class<?>[]{apiClass},
          (proxy, method, args) -> {
            if ("newParser".equals(method.getName())) {
              return parserMock;
            }
            if (method.getReturnType().isPrimitive()) {
              if (method.getReturnType() == boolean.class) return false;
              if (method.getReturnType() == byte.class) return (byte) 0;
              if (method.getReturnType() == short.class) return (short) 0;
              if (method.getReturnType() == int.class) return 0;
              if (method.getReturnType() == long.class) return 0L;
              if (method.getReturnType() == float.class) return 0f;
              if (method.getReturnType() == double.class) return 0d;
              if (method.getReturnType() == char.class) return '\0';
            }
            return null;
          });

      // Inject mocks into private fields using reflection
      Field documentField = ParseBenchmark.class.getDeclaredField("document");
      documentField.setAccessible(true);
      documentField.set(parseBenchmark, documentProxy);

      Field apiField = ParseBenchmark.class.getDeclaredField("api");
      apiField.setAccessible(true);
      apiField.set(parseBenchmark, apiProxy);

    } catch (Exception e) {
      throw new RuntimeException(e);
    }

    // Use reflection to get the private static method resourceToString
    Method resourceToStringMethod = ParseBenchmark.class.getDeclaredMethod("resourceToString", String.class);
    resourceToStringMethod.setAccessible(true);

    // Mock static method resourceToString to return a JSON string
    try (MockedStatic<ParseBenchmark> mockedStatic = Mockito.mockStatic(ParseBenchmark.class, invocation -> {
      if (invocation.getMethod().equals(resourceToStringMethod)) {
        return "{\"key\":\"value\"}";
      }
      return invocation.callRealMethod();
    })) {

      // Use reflection to invoke private setUp method
      Method setUpMethod = ParseBenchmark.class.getDeclaredMethod("setUp");
      setUpMethod.setAccessible(true);
      setUpMethod.invoke(parseBenchmark);

      // Verify that text field is set correctly (char array of returned string)
      Field textField = ParseBenchmark.class.getDeclaredField("text");
      textField.setAccessible(true);
      char[] textValue = (char[]) textField.get(parseBenchmark);
      assertArrayEquals("{\"key\":\"value\"}".toCharArray(), textValue);

      // Verify that parser field is set to the mocked parser
      Field parserField = ParseBenchmark.class.getDeclaredField("parser");
      parserField.setAccessible(true);
      Object parserValue = parserField.get(parseBenchmark);
      assertSame(parserMock, parserValue);

      // Create a spy for apiProxy to verify newParser calls
      Object apiSpy = spy(apiProxy);
      Field apiField = ParseBenchmark.class.getDeclaredField("api");
      apiField.setAccessible(true);
      apiField.set(parseBenchmark, apiSpy);

      // Call setUp again to trigger newParser call on spy
      setUpMethod.invoke(parseBenchmark);

      // Verify newParser was called twice (once before spy, once after)
      // Mockito cannot verify calls on proxy methods directly, so verify invocation count on spy's invocation handler
      verify(apiSpy, times(2)).getClass();

      // Verify that resourceToString was called twice with expected argument
      mockedStatic.verify(() -> resourceToStringMethod.invoke(null, "testdoc.json"), times(2));
    }
  }
}
